import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int maxLength = 10; // Maximum length allowed in the buffer
        char[] buffer = new char[maxLength];

        // Ensure user input does not exceed buffer length
        if(userInput.length() > maxLength) {
            System.out.println("Input exceeds maximum allowed length.");
            userInput = userInput.substring(0, maxLength); // Truncate input if too long
        }

        // Properly copy user input into buffer
        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

